// Get current execution state from static data
const staticData = $getWorkflowStaticData('global');
const items = $input.all();

// Initialize static data if needed
if (!staticData.executions) {
  staticData.executions = {};
}

// Update with incoming data if from webhook
if (items.length > 0 && items[0].json.jira_ticket) {
  const data = items[0].json;
  const execId = data.run_id || data.jira_ticket;

  if (!staticData.executions[execId]) {
    staticData.executions[execId] = {
      jira_ticket: data.jira_ticket,
      start_time: new Date().toISOString(),
      phases: {},
      agents: {},
      metrics: {}
    };
  }

  // Update based on type
  if (data.type === 'framework_update') {
    staticData.executions[execId].phases[data.phase] = {
      status: data.status,
      timestamp: data.timestamp,
      agents: data.agents
    };
  } else if (data.type === 'agent_update') {
    staticData.executions[execId].agents[data.agent] = {
      status: data.status,
      confidence: data.confidence,
      execution_time: data.execution_time,
      timestamp: data.timestamp
    };
  }

  staticData.current_execution = execId;
}

// Get current execution
const currentExecId = staticData.current_execution;
const currentExec = staticData.executions[currentExecId] || {};

// Build visual state
const visualState = {
  jira_ticket: currentExec.jira_ticket || 'No Active Execution',
  timestamp: new Date().toISOString(),

  // Phase states with visual indicators
  phases: {
    initialization: getPhaseVisualState(currentExec.phases?.initialization),
    foundation_analysis: getPhaseVisualState(currentExec.phases?.foundation_analysis),
    deep_investigation: getPhaseVisualState(currentExec.phases?.deep_investigation),
    qe_intelligence: getPhaseVisualState(currentExec.phases?.qe_intelligence),
    ai_analysis: getPhaseVisualState(currentExec.phases?.ai_analysis),
    test_generation: getPhaseVisualState(currentExec.phases?.test_generation),
    cleanup: getPhaseVisualState(currentExec.phases?.cleanup)
  },

  // Agent states with visual indicators
  agents: {
    agent_a: getAgentVisualState(currentExec.agents?.agent_a, 'JIRA Intelligence'),
    agent_d: getAgentVisualState(currentExec.agents?.agent_d, 'Environment Assessment'),
    agent_b: getAgentVisualState(currentExec.agents?.agent_b, 'Documentation Analysis'),
    agent_c: getAgentVisualState(currentExec.agents?.agent_c, 'GitHub Investigation')
  },

  // Overall metrics
  metrics: {
    overall_progress: calculateProgress(currentExec),
    active_phase: getActivePhase(currentExec),
    active_agents: getActiveAgents(currentExec),
    execution_time: getExecutionTime(currentExec),
    completion_estimate: getCompletionEstimate(currentExec)
  }
};

function getPhaseVisualState(phase) {
  if (!phase) return { status: 'pending', icon: '⏳', color: '#666' };

  const states = {
    'starting': { icon: '🔄', color: '#ff9800', animation: 'pulse' },
    'running': { icon: '⚡', color: '#2196f3', animation: 'pulse' },
    'completed': { icon: '✅', color: '#4caf50', animation: 'none' },
    'failed': { icon: '❌', color: '#f44336', animation: 'shake' }
  };

  return states[phase.status] || { status: phase.status, icon: '❓', color: '#999' };
}

function getAgentVisualState(agent, name) {
  const state = {
    name: name,
    status: agent?.status || 'inactive',
    confidence: agent?.confidence || null,
    execution_time: agent?.execution_time || null
  };

  const visualStates = {
    'inactive': { icon: '⚪', color: '#666', glow: false },
    'starting': { icon: '🔄', color: '#ff9800', glow: true },
    'running': { icon: '⚡', color: '#2196f3', glow: true },
    'completed': { icon: '✅', color: '#4caf50', glow: false },
    'failed': { icon: '❌', color: '#f44336', glow: false }
  };

  return { ...state, ...visualStates[state.status] };
}

function calculateProgress(exec) {
  const phases = Object.values(exec.phases || {});
  if (phases.length === 0) return 0;

  const weights = {
    'initialization': 5,
    'foundation_analysis': 20,
    'deep_investigation': 20,
    'qe_intelligence': 10,
    'ai_analysis': 20,
    'test_generation': 20,
    'cleanup': 5
  };

  let progress = 0;
  Object.entries(exec.phases || {}).forEach(([phaseName, phase]) => {
    if (phase.status === 'completed') {
      progress += weights[phaseName] || 0;
    } else if (phase.status === 'running') {
      progress += (weights[phaseName] || 0) * 0.5;
    }
  });

  return Math.round(progress);
}

function getActivePhase(exec) {
  const phaseOrder = ['initialization', 'foundation_analysis', 'deep_investigation', 'qe_intelligence', 'ai_analysis', 'test_generation', 'cleanup'];

  for (const phaseName of phaseOrder) {
    const phase = exec.phases?.[phaseName];
    if (phase?.status === 'running' || phase?.status === 'starting') {
      return phaseName.replace(/_/g, ' ').toUpperCase();
    }
  }

  return 'IDLE';
}

function getActiveAgents(exec) {
  return Object.entries(exec.agents || {})
    .filter(([_, agent]) => agent.status === 'running' || agent.status === 'starting')
    .map(([name, _]) => name.replace(/_/g, ' ').toUpperCase());
}

function getExecutionTime(exec) {
  if (!exec.start_time) return '00:00:00';

  const start = new Date(exec.start_time);
  const now = new Date();
  const diff = now - start;

  const hours = Math.floor(diff / 3600000);
  const minutes = Math.floor((diff % 3600000) / 60000);
  const seconds = Math.floor((diff % 60000) / 1000);

  return `${hours.toString().padStart(2, '0')}:${minutes.toString().padStart(2, '0')}:${seconds.toString().padStart(2, '0')}`;
}

function getCompletionEstimate(exec) {
  const progress = calculateProgress(exec);
  if (progress === 0) return 'Not started';
  if (progress === 100) return 'Completed';

  // Estimate based on current progress and time
  const elapsedMinutes = exec.start_time ? (new Date() - new Date(exec.start_time)) / 60000 : 0;
  const estimatedTotal = elapsedMinutes / (progress / 100);
  const remainingMinutes = Math.round(estimatedTotal - elapsedMinutes);

  if (remainingMinutes < 1) return 'Less than 1 minute';
  if (remainingMinutes < 60) return `~${remainingMinutes} minutes`;

  const hours = Math.floor(remainingMinutes / 60);
  const mins = remainingMinutes % 60;
  return `~${hours}h ${mins}m`;
}

return [{ json: visualState }];

